from __future__ import annotations


def bitrix_onec_integration_dashboard_html() -> str:
    return r'''<!doctype html><html lang="ru"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Bitrix24 ↔ 1С Integration Audit — AI-BIT</title><style>
:root{color-scheme:light;--bg:#f5f6f8;--surface:#fff;--surface2:#fafbfc;--line:#e3e6ea;--text:#17191c;--muted:#70757d;--accent:#5e6ad2;--ok:#16835d;--warn:#a9670b;--bad:#b42318;--mono:ui-monospace,SFMono-Regular,Consolas,monospace}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font:13px/1.45 Inter,Segoe UI,sans-serif}main{max-width:1680px;margin:auto;padding:24px 26px 80px}.head{display:flex;justify-content:space-between;gap:20px;margin-bottom:14px}.eyebrow{font-size:10px;font-weight:800;letter-spacing:.12em;text-transform:uppercase;color:var(--accent)}h1{font-size:25px;margin:4px 0}.muted{color:var(--muted)}.actions{display:flex;gap:8px}.btn{border:1px solid var(--line);background:#fff;border-radius:7px;padding:8px 11px;cursor:pointer}.btn.primary{background:#202124;color:#fff;border-color:#202124}.policy,.metrics{display:flex;gap:8px;flex-wrap:wrap;margin-bottom:12px}.chip,.metric{background:#fff;border:1px solid var(--line);border-radius:9px;padding:8px 11px}.metric span{display:block;color:var(--muted);font-size:10px;text-transform:uppercase}.metric b{font-size:21px}.tabs{display:flex;gap:4px;overflow:auto;border-bottom:1px solid var(--line);margin-bottom:12px}.tab{border:0;background:transparent;padding:9px 11px;color:#666b73;cursor:pointer;border-bottom:2px solid transparent;white-space:nowrap}.tab.active{border-bottom-color:var(--accent);color:var(--text);font-weight:700}.view{display:none}.view.active{display:block}.panel{background:#fff;border:1px solid var(--line);border-radius:10px;overflow:hidden;margin-bottom:10px}.panel-head{display:flex;justify-content:space-between;align-items:center;padding:12px 14px;background:var(--surface2);border-bottom:1px solid var(--line)}.panel-head h2{font-size:14px;margin:0}.count{font:11px var(--mono);color:var(--muted)}table{width:100%;border-collapse:collapse}th,td{padding:9px 11px;text-align:left;border-bottom:1px solid #edf0f2;vertical-align:top}th{font-size:10px;text-transform:uppercase;color:var(--muted);background:#fbfcfd}tr:last-child td{border-bottom:0}.mono{font-family:var(--mono);font-size:11px;word-break:break-word}.badge{display:inline-flex;border-radius:999px;padding:3px 7px;font-size:10px;font-weight:800;text-transform:uppercase}.confirmed,.ready{background:#e7f6ef;color:var(--ok)}.partial,.attention{background:#fff3dc;color:var(--warn)}.insufficient_data,.error{background:#fee4e2;color:var(--bad)}.grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px}.card{background:#fff;border:1px solid var(--line);border-radius:9px;padding:12px}.card h3{margin:0 0 8px;font-size:13px}.row{display:flex;justify-content:space-between;gap:16px;padding:5px 0;border-bottom:1px solid #eef0f2}.row:last-child{border:0}.empty{padding:28px;text-align:center;color:var(--muted);background:#fff;border:1px solid var(--line);border-radius:9px}.error-panel{display:none;padding:16px;border:1px solid #f1c5cb;background:#fff7f8;color:#8f2433;border-radius:9px;margin-bottom:10px}.error-panel.show{display:block}@media(max-width:850px){.grid{grid-template-columns:1fr}.head{display:block}.actions{margin-top:10px}}
</style></head><body><main><div class="head"><div><div class="eyebrow">AI-BIT Enterprise 4.3</div><h1>Bitrix24 ↔ 1С Integration Audit</h1><div class="muted">Топология · целостность данных · синхронизация · Implementation Blueprint</div></div><div class="actions"><button class="btn" id="json">JSON</button><button class="btn primary" id="run">Запустить аудит</button></div></div><div id="error" class="error-panel"></div><div id="policy" class="policy"></div><div id="metrics" class="metrics"></div><nav id="tabs" class="tabs"><button class="tab active" data-view="overview">Обзор</button><button class="tab" data-view="topology">Топология</button><button class="tab" data-view="fields">Поля</button><button class="tab" data-view="data">Данные</button><button class="tab" data-view="sync">Синхронизация</button><button class="tab" data-view="findings">Отклонения</button><button class="tab" data-view="blueprint">Blueprint</button><button class="tab" data-view="mcp">MCP-план</button></nav><section id="overview" class="view active"></section><section id="topology" class="view"></section><section id="fields" class="view"></section><section id="data" class="view"></section><section id="sync" class="view"></section><section id="findings" class="view"></section><section id="blueprint" class="view"></section><section id="mcp" class="view"></section></main><script>
(()=>{'use strict';const q=(s,r=document)=>r.querySelector(s);const qa=(s,r=document)=>Array.from(r.querySelectorAll(s));const esc=v=>String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));let data=null;function badge(v){const x=String(v||'insufficient_data');return `<span class="badge ${esc(x)}">${esc(x)}</span>`}function panel(title,body,count=''){return `<div class="panel"><div class="panel-head"><h2>${esc(title)}</h2><span class="count">${esc(count)}</span></div>${body}</div>`}function table(headers,rows){if(!rows.length)return '<div class="empty">Подтверждённых данных пока нет.</div>';return `<table><thead><tr>${headers.map(x=>`<th>${esc(x)}</th>`).join('')}</tr></thead><tbody>${rows.join('')}</tbody></table>`}function render(){const s=data.summary||{},p=data.execution_policy||{};q('#policy').innerHTML=[`mode: ${data.mode}`,`Bitrix write: ${p.bitrix_write}`,`1C write: ${p.onec_write}`,`REST execution: ${p.rest_execution}`,`proposals only: ${p.proposals_only}`].map(x=>`<span class="chip mono">${esc(x)}</span>`).join('');q('#metrics').innerHTML=[['Status',badge(data.status)],['Confirmed',s.confirmed||0],['Partial',s.partial||0],['Insufficient',s.insufficient_data||0],['Findings',s.findings||0]].map(x=>`<div class="metric"><span>${x[0]}</span><b>${x[1]}</b></div>`).join('');const src=data.sources||{};q('#overview').innerHTML=panel('Готовность источников',`<div class="grid" style="padding:10px"><div class="card"><h3>Bitrix24</h3><div class="row"><span>Evidence</span>${badge(src.bitrix?'confirmed':'insufficient_data')}</div></div><div class="card"><h3>1С MCP</h3><div class="row"><span>Evidence</span>${badge(src.onec_mcp?'confirmed':'insufficient_data')}</div></div></div>`)+panel('Принцип',`<div style="padding:13px 14px">Вывод формируется только при наличии подтверждений с обеих сторон. Отсутствие evidence не трактуется как отсутствие объекта.</div>`,data.version||'');const top=data.topology||[];q('#topology').innerHTML=panel('Карта соответствия',table(['Статус','Связка','Bitrix24','1С','BX evidence','1C evidence'],top.map(x=>`<tr><td>${badge(x.status)}</td><td><b>${esc(x.label)}</b></td><td class="mono">${esc(x.bitrix_object)}</td><td class="mono">${esc(x.onec_object)}</td><td>${x.bitrix_evidence?'yes':'no'}</td><td>${x.onec_evidence?'yes':'no'}</td></tr>`)),`${top.length} mappings`);const fld=data.field_integrity||[];q('#fields').innerHTML=panel('Маппинг полей',table(['Статус','Сущность','Bitrix поле','1С поле','BX evidence','1C evidence'],fld.map(x=>`<tr><td>${badge(x.status)}</td><td>${esc(x.entity)}</td><td class="mono">${esc(x.bitrix_field)}</td><td class="mono">${esc(x.onec_field)}</td><td>${x.bitrix_evidence?'yes':'no'}</td><td>${x.onec_evidence?'yes':'no'}</td></tr>`)),`${fld.length} rules`);const d=data.data_integrity||[];q('#data').innerHTML=panel('Проверки данных',table(['Статус','Проверка','Bitrix источник','1С call id'],d.map(x=>`<tr><td>${badge(x.status)}</td><td><b>${esc(x.label)}</b></td><td class="mono">${esc(x.bitrix_source||'')}</td><td class="mono">${esc(x.onec_call_id||'')}</td></tr>`)),`${d.length} checks`);const sy=data.synchronization||{};q('#sync').innerHTML=panel('Диагностика синхронизации',`<div style="padding:12px 14px"><div class="row"><span>Статус</span>${badge(sy.status)}</div><div class="row"><span>Bitrix snapshot</span><b>${sy.bitrix_snapshot_available?'yes':'no'}</b></div><div class="row"><span>1С event log</span><b>${sy.onec_event_log_available?'yes':'no'}</b></div><div class="row"><span>Событий интеграции</span><b>${sy.matching_events_count||0}</b></div><p class="muted">${esc(sy.note||'')}</p></div>`);const f=data.findings||[];q('#findings').innerHTML=panel('Подтверждённые отклонения',table(['Severity','Area','Факт','Действие'],f.map(x=>`<tr><td>${badge(x.severity)}</td><td class="mono">${esc(x.area)}</td><td>${esc(x.fact)}</td><td>${esc(x.action)}</td></tr>`)),`${f.length} findings`);const b=data.implementation_blueprint||[];q('#blueprint').innerHTML=panel('Implementation Blueprint',table(['#','Area','Задача','Основание','Приёмка','Режим'],b.map(x=>`<tr><td class="mono">${x.priority}</td><td class="mono">${esc(x.area)}</td><td>${esc(x.task)}</td><td>${esc(x.basis)}</td><td>${esc(x.acceptance)}</td><td>${badge(x.execution)}</td></tr>`)),`${b.length} tasks`);const m=data.required_mcp_calls||[];q('#mcp').innerHTML=panel('Рекомендуемый read-only MCP-план',table(['ID','Tool','Arguments'],m.map(x=>`<tr><td class="mono">${esc(x.id)}</td><td class="mono">${esc(x.name)}</td><td><pre class="mono" style="white-space:pre-wrap;margin:0">${esc(JSON.stringify(x.arguments||{},null,2))}</pre></td></tr>`)),`${m.length} calls`)}async function load(run=false){const btn=q('#run');btn.disabled=true;q('#error').classList.remove('show');try{const r=await fetch(run?'/bitrix-onec-integration/collect':'/bitrix-onec-integration/latest',{method:run?'POST':'GET',cache:'no-store'});if(!r.ok)throw new Error(await r.text());data=await r.json();render()}catch(e){q('#error').textContent=e.message;q('#error').classList.add('show')}finally{btn.disabled=false}}q('#tabs').addEventListener('click',e=>{const b=e.target.closest('[data-view]');if(!b)return;qa('.tab,.view').forEach(x=>x.classList.remove('active'));b.classList.add('active');q('#'+b.dataset.view)?.classList.add('active')});q('#run').onclick=()=>load(true);q('#json').onclick=()=>{if(!data)return;const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([JSON.stringify(data,null,2)],{type:'application/json'}));a.download='bitrix-onec-integration-audit.json';a.click();URL.revokeObjectURL(a.href)};load(false)})();
</script></body></html>'''
